    @GetResource(path = "/export", requiredPermission = false)
    @Operation(summary = "Export feedback as CSV")
    public void exportFeedbackCsv(FeedbackListRo ro, HttpServletResponse response) throws IOException {
        byte[] csvBytes = feedbackService.exportFeedbackCsv(ro);

        String fileName = "反馈收集_" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE) + ".csv";
        String encodedFileName = URLEncoder.encode(fileName, StandardCharsets.UTF_8).replace("+", "%20");

        response.setContentType("text/csv; charset=UTF-8");
        response.setHeader("Content-Disposition", "attachment; filename*=UTF-8''" + encodedFileName);
        response.setContentLength(csvBytes.length);
        response.getOutputStream().write(csvBytes);
        response.getOutputStream().flush();
    }
}

