async function test_1_normal_export() {
  console.log('📋 §1. 正常导出CSV');

  const res = await GET_RAW('/feedback/export');
  assert('§1.正常导出 - HTTP状态码200', res.status === 200, res.status);
  assert('§1.正常导出 - Content-Type为text/csv', res.headers.get('content-type')?.includes('text/csv'), res.headers.get('content-type'));
  assert('§1.正常导出 - Content-Disposition包含attachment', res.headers.get('content-disposition')?.includes('attachment'), res.headers.get('content-disposition'));
  assert('§1.正常导出 - 文件名包含.csv', res.headers.get('content-disposition')?.includes('.csv'), res.headers.get('content-disposition'));

  const text = await res.text();
  assert('§1.正常导出 - 响应体非空', text.length > 0, text.length);
  assert('§1.正常导出 - 包含UTF-8 BOM', text.charCodeAt(0) === 0xFEFF, `charCode=${text.charCodeAt(0)}`);

  const { headers, rows } = parseCsv(text);
  assert('§1.正常导出 - 表头11列', headers.length === 11, headers);
  assert('§1.正常导出 - 表头第1列=反馈人', headers[0] === '反馈人', headers[0]);
  assert('§1.正常导出 - 表头第2列=用户ID', headers[1] === '用户ID', headers[1]);
  assert('§1.正常导出 - 表头第11列=处理状态', headers[10] === '处理状态', headers[10]);
  assert('§1.正常导出 - 数据行数>0', rows.length > 0, rows.length);
  console.log(`   ℹ️  共导出 ${rows.length} 行数据`);
}

